import{c as o,Q as a,j as n,m as r}from"./chunks/framework.DpF7k2f3.js";const q=JSON.parse('{"title":"","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"zh/part1-cognition/chapter1.md","filePath":"zh/part1-cognition/chapter1.md"}'),p={name:"zh/part1-cognition/chapter1.md"};function l(s,t,e,i,u,g){return a(),n("div",null,[...t[0]||(t[0]=[r(`<h5 id="第1章-ai应用开发的真相" tabindex="-1">第1章 AI应用开发的真相 <a class="header-anchor" href="#第1章-ai应用开发的真相" aria-label="Permalink to &quot;第1章 AI应用开发的真相&quot;">​</a></h5><h4 id="本章你能带走什么" tabindex="-1">本章你能带走什么 <a class="header-anchor" href="#本章你能带走什么" aria-label="Permalink to &quot;本章你能带走什么&quot;">​</a></h4><p>读这一章之前，你可能觉得AI应用开发是个高不可攀的领域——需要PhD、需要懂Transformer架构、需要数学功底扎实。</p><p>读完这章你会知道：</p><ul><li>AI应用开发和AI研究是两码事，入行门槛完全不在一个量级</li><li>2024-2026年行业发生了什么变化，为什么现在是入场最好时机</li><li>招聘JD里哪些要求是真的、哪些是虚的，别被吓住</li><li>8个真实转行案例告诉你，不同背景的人是怎么混进来的</li></ul><hr><h4 id="_1-1-什么是ai应用开发-vs-ai研究-ai基础设施" tabindex="-1">1.1 什么是AI应用开发（vs AI研究/AI基础设施） <a class="header-anchor" href="#_1-1-什么是ai应用开发-vs-ai研究-ai基础设施" aria-label="Permalink to &quot;1.1 什么是AI应用开发（vs AI研究/AI基础设施）&quot;">​</a></h4><p>先说个扎心的真相：大部分人想进的&quot;AI岗&quot;，其实根本不是他们以为的那个&quot;AI岗&quot;。</p><h6 id="三个工种-一字之差-天壤之别" tabindex="-1">三个工种，一字之差，天壤之别 <a class="header-anchor" href="#三个工种-一字之差-天壤之别" aria-label="Permalink to &quot;三个工种，一字之差，天壤之别&quot;">​</a></h6><p>我把AI行业的技术岗位分成三层，你搞清楚自己在哪一层，就不会走错路：</p><p><strong>第一层：AI研究（Research）</strong></p><p>这是做基础创新的。做什么？训练新模型、改进Transformer架构、搞Attention机制优化。OpenAI、Google DeepMind、Anthropic的科学家们干的就是这个。</p><p>门槛有多高？这么说吧，能在这个层立足的人，全球范围内也就几万人级别的顶尖人才（据多方数据估算，全球AI研究人员约20万，但能真正做基础创新的只是其中一小撮）。你需要：顶会论文、PhD学位（或同等科研能力）、扎实的数学功底、对最新论文了如指掌。</p><p>薪资？天文数字。但跟你我没关系。</p><p><strong>第二层：AI基础设施（Infrastructure）</strong></p><p>这是给&quot;上面那层&quot;造工具的。做什么？训练框架开发（PyTorch/TensorFlow维护）、推理引擎优化（vLLM/TensorRT）、分布式训练系统、GPU集群管理。</p><p>门槛同样不低。需要懂系统底层、C++能力、深度学习框架原理。薪资略低于研究岗，但也绝对高薪。</p><p><strong>第三层：AI应用开发（Application）</strong></p><p>这就是我们这本书要讲的东西。也是你大概率能进去的那层。</p><p>做什么？说白了就是&quot;用AI能力解决业务问题&quot;。具体点：</p><ul><li>搭RAG系统让大模型能回答私有知识库的问题</li><li>写Prompt让AI按你想要的格式输出</li><li>搭Agent让AI能自动执行多步任务</li><li>对接API把AI能力集成到产品里</li></ul><p>你不需要训练模型，不需要懂梯度反向传播，不需要手推Attention公式。你需要的是：<strong>把现有AI能力用好，用到业务场景里，产生商业价值。</strong></p><h6 id="打个比方你就明白了" tabindex="-1">打个比方你就明白了 <a class="header-anchor" href="#打个比方你就明白了" aria-label="Permalink to &quot;打个比方你就明白了&quot;">​</a></h6><p>造车是研究，制造发动机是基础设施，修车+改装是应用。</p><p>你会觉得修车师傅需要懂发动机燃烧室原理吗？懂当然更好，但不懂也能干活。修车师傅需要的是：知道怎么用工具、知道常见问题怎么修、知道客户要什么。</p><p>AI应用开发同理。你不需要从零训练模型，你需要的是：知道怎么调API、知道常见坑怎么踩、知道业务场景怎么落地。</p><h6 id="市场需求在哪一边" tabindex="-1">市场需求在哪一边？ <a class="header-anchor" href="#市场需求在哪一边" aria-label="Permalink to &quot;市场需求在哪一边？&quot;">​</a></h6><p>2025年的数据最能说明问题。据脉脉高聘人才报告显示，AI产品经理岗位量同比增长369.36%，远超算法岗位的248.65%。腾讯、京东、百度开放的技术岗中，80%与大模型应用相关。</p><p>企业缺的不是能发明新算法的人，而是能把AI产品化的人。这才是市场真相。</p><p><strong>一句话总结：AI应用开发 = 借助现有AI能力解决实际业务问题。不造轮子，只做轮子的搬运工和组装工。</strong></p><hr><h4 id="_1-2-2024-2026行业演变-从prompt工程到agent工程" tabindex="-1">1.2 2024-2026行业演变：从Prompt工程到Agent工程 <a class="header-anchor" href="#_1-2-2024-2026行业演变-从prompt工程到agent工程" aria-label="Permalink to &quot;1.2 2024-2026行业演变：从Prompt工程到Agent工程&quot;">​</a></h4><p>如果你2023年关注AI行业，听到最多的词可能是&quot;Prompt工程&quot;。到2025年，这个词几乎销声匿迹，取而代之的是&quot;Agent工程&quot;。</p><p>这两年的变化，用&quot;天翻地覆&quot;来形容不为过。</p><h6 id="_2023-2024-prompt工程师的短暂春天" tabindex="-1">2023-2024：Prompt工程师的短暂春天 <a class="header-anchor" href="#_2023-2024-prompt工程师的短暂春天" aria-label="Permalink to &quot;2023-2024：Prompt工程师的短暂春天&quot;">​</a></h6><p>2023年初ChatGPT爆火时，行业冒出一个新岗位叫&quot;Prompt工程师&quot;——就是写提示词让AI输出更好结果的人。</p><p>那时候真有人靠&quot;调教&quot;AI聊天机器人拿到了高薪。一些猎头甚至放话：&quot;prompt engineer，年薪50万起步&quot;。</p><p>但这个岗位的繁荣建立在一个前提上：<strong>那时候的AI还比较蠢，需要人工精心设计提示词才能用好。</strong></p><p>结果呢？2024年初，Claude 3、GPT-4o、Gemini 1.5这些模型一出来，prompt engineer的需求直接腰斩——模型变聪明了，不需要那么多&quot;咒语&quot;了。</p><p>这波红利期的窗口有多短？满打满算不到18个月。</p><p><strong>教训：别追着风口跑，风口会变。</strong></p><h6 id="_2024-2025-agent工程的爆发" tabindex="-1">2024-2025：Agent工程的爆发 <a class="header-anchor" href="#_2024-2025-agent工程的爆发" aria-label="Permalink to &quot;2024-2025：Agent工程的爆发&quot;">​</a></h6><p>当Prompt工程退潮时，一个更大的浪潮已经涌来——AI Agent（智能体）。</p><p>什么是Agent？简单说就是：<strong>让AI从&quot;你问我答&quot;的被动模式，变成&quot;你给我目标，我自主执行&quot;的主动模式。</strong></p><p>举个例子：</p><ul><li>普通AI：输入&quot;帮我写一封请假邮件&quot;→ 输出邮件内容</li><li>Agent：输入&quot;帮我请下周三的假&quot;→ Agent自动查日历→ 发现周三有会议→ 自动改期→ 生成邮件→ 发给你确认→ 你说OK→ Agent发送邮件</li></ul><p>看到了吗？Agent会自主规划、自主调用工具、自主执行多步任务。相当于从&quot;工具&quot;升级成了&quot;助理&quot;。</p><p>这个升级意味着什么？意味着AI能真正替代部分白领工作了。</p><p>企业当然疯狂跟进。2026年Q1数据显示，Agent工程师岗位同比增长310%，供需比达到1:7.5到1:8.2的极端失衡状态。人才供给端，全国仅6-8万人具备Agent开发经验，资深人才不足1.5万。</p><p><strong>多Agent协作系统工程师年薪中位数达95万元，较传统LLM算法工程师溢价58%。</strong></p><p>这不是小打小闹，这是真金白银的人才战争。</p><h6 id="框架生态的爆发" tabindex="-1">框架生态的爆发 <a class="header-anchor" href="#框架生态的爆发" aria-label="Permalink to &quot;框架生态的爆发&quot;">​</a></h6><p>需求带动工具。2024年到2025年，AI开发框架生态疯狂成熟：</p><ul><li><strong>LangChain</strong>：从玩具到生产级工具，生态越来越完善</li><li><strong>LlamaIndex</strong>：专注RAG，成为向量检索的主流选择</li><li><strong>CrewAI、AutoGen</strong>：多Agent协作框架，让你用几行代码搭出Agent团队</li><li><strong>Dify、Coze</strong>：低代码AI应用平台，非技术背景也能快速搭建AI应用</li></ul><p>换句话说：<strong>两年前你可能需要手写几百行代码才能实现的功能，现在用现成框架可能几十分钟就搞定了。</strong></p><p>门槛在快速下降。这也是为什么我现在说&quot;先混进去&quot;是可行的——因为工具链已经成熟到不需要那么高的学习成本。</p><h6 id="技术栈的演进路线" tabindex="-1">技术栈的演进路线 <a class="header-anchor" href="#技术栈的演进路线" aria-label="Permalink to &quot;技术栈的演进路线&quot;">​</a></h6><p>如果你是2024年入行，需要掌握的技术栈大概是：</p><ul><li>Prompt工程（基础）</li><li>API调用（OpenAI/Claude/国产模型）</li><li>RAG（检索增强生成）</li><li>LangChain或LlamaIndex（框架）</li></ul><p>如果你是2025-2026年入行，除了上面的，还需要：</p><ul><li>Agent设计（ReAct、Plan-and-Execute等模式）</li><li>多Agent协作</li><li>工具调用（Function Calling）</li><li>生产级部署（FastAPI + Docker + vLLM）</li></ul><p>看起来要求变高了？别慌。框架成熟了，学习曲线反而比两年前更平缓。你需要学的是&quot;如何用好工具&quot;，而不是&quot;如何造工具&quot;。</p><p><strong>一句话总结：从Prompt工程到Agent工程，是AI从&quot;玩具&quot;到&quot;工具&quot;再到&quot;助理&quot;的进化。现在入场，你踩的是成熟的生态，不是荒芜的土地。</strong></p><hr><h4 id="_1-3-招聘jd解读-哪些是硬门槛-哪些是虚晃一枪" tabindex="-1">1.3 招聘JD解读：哪些是硬门槛，哪些是虚晃一枪 <a class="header-anchor" href="#_1-3-招聘jd解读-哪些是硬门槛-哪些是虚晃一枪" aria-label="Permalink to &quot;1.3 招聘JD解读：哪些是硬门槛，哪些是虚晃一枪&quot;">​</a></h4><p>每次看到招聘JD，我都替求职者捏把汗——那些写得吓死人的要求，到底是真是假？</p><p>让我来帮你拆解。</p><h6 id="硬门槛-真的需要" tabindex="-1">硬门槛（真的需要） <a class="header-anchor" href="#硬门槛-真的需要" aria-label="Permalink to &quot;硬门槛（真的需要）&quot;">​</a></h6><p><strong>1. Python编程能力</strong></p><p>这个没得商量。不管你怎么包装，代码总得写。API调用要写Python、RAG实现要写Python、Agent逻辑要写Python。</p><p>需要到什么程度？能独立完成脚本开发、懂基本的数据结构、写过面向对象的代码。大概是&quot;初级工程师&quot;的水平，不用到&quot;架构师&quot;级别。</p><p>怎么证明？GitHub上有自己的小项目、能现场写个简单函数、面试能聊几句Python协程。</p><p><strong>2. 对AI API的熟悉度</strong></p><p>能独立调用OpenAI/Claude/国产模型的API，理解system prompt、temperature、max_tokens这些参数的意义，知道什么叫JSON mode什么叫function calling。</p><p>这个不难，花一周时间看文档+写几个demo就能入门。</p><p><strong>3. 基本的系统设计能力</strong></p><p>不是说你得设计过千万日活的系统，但至少要能说清楚：你的RAG系统怎么选文档切分策略、怎么选向量数据库、怎么评估效果。</p><p>有实际项目经验（哪怕是demo级别）的人，这个能聊。没有的，就只能靠背题了。</p><p><strong>4. 对至少一个主流框架的实战经验</strong></p><p>LangChain、LlamaIndex、FastAPI、vLLM……不需要全都会，但至少有一个能拿出来说的&quot;实战项目&quot;。</p><hr><h6 id="虚晃一枪-别被吓住" tabindex="-1">虚晃一枪（别被吓住） <a class="header-anchor" href="#虚晃一枪-别被吓住" aria-label="Permalink to &quot;虚晃一枪（别被吓住）&quot;">​</a></h6><p><strong>1. &quot;985/211硕士及以上学历&quot;</strong></p><p>很多人看到这条就放弃了。其实这条弹性很大。</p><p>大厂的校招确实卡学历，但：</p><ul><li>中小厂、外包、创业公司往往不硬卡</li><li>社招更看项目经验，学历权重降低</li><li>很多公司写着&quot;本科及以上&quot;，实际进入的专科也有</li></ul><p>更关键的是：<strong>你投的是应用开发岗，不是研究岗。能力比学历管用。</strong></p><p><strong>2. &quot;精通机器学习/深度学习原理&quot;</strong></p><p>这条在招&quot;算法工程师&quot;时可能是真的，在招&quot;应用开发&quot;时往往是JD模板没改。</p><p>什么叫&quot;精通&quot;？能推导反向传播？能手写Attention？老实说，应用开发里根本用不到这些。</p><p>你需要知道的是：<strong>大模型能做什么、不能做什么、怎么调用、怎么评估</strong>。这些不需要&quot;精通原理&quot;。</p><p>当然，了解一些基本概念有帮助。但&quot;精通&quot;和&quot;了解&quot;差了十万八千里，别被这个词吓住。</p><p><strong>3. &quot;有GPT-4/Claude实战经验&quot;</strong></p><p>这条更虚。会用ChatGPT不等于会做AI开发，但如果你连AI对话产品都没用过，那确实说不过去。</p><p>所以这条其实是：<strong>别是纯外行就行。</strong> 只要你日常用过AI工具，了解AI能做什么、做不到什么，就够了。</p><p><strong>4. &quot;发表过顶会论文/开源项目star过千&quot;</strong></p><p>这种要求只出现在大厂核心团队的研究岗。普通应用开发岗根本不会提这种要求——写了也是HR复制粘贴的。</p><p>除非你投的是OpenAI、Anthropic或者国内顶尖AI实验室的研究岗，否则别被这条唬住。</p><p><strong>5. &quot;有AIGC产品落地经验&quot;</strong></p><p>这条是2024-2025年最常见的&quot;虚假门槛&quot;。企业想找有经验的人，但2023年哪有什么AIGC产品落地？</p><p>所以这条的真实含义是：<strong>最好有demo，没demo的话有学习能力也行。</strong> 关键看你能不能证明自己不是在&quot;纸上谈兵&quot;。</p><hr><h6 id="真实jd解析" tabindex="-1">真实JD解析 <a class="header-anchor" href="#真实jd解析" aria-label="Permalink to &quot;真实JD解析&quot;">​</a></h6><p>我来拆解一个真实的招聘JD，让你看看表面之下是什么：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>岗位职责：</span></span>
<span class="line"><span>1. 负责AI应用产品的设计和开发</span></span>
<span class="line"><span>2. 搭建RAG系统，实现知识库问答</span></span>
<span class="line"><span>3. 开发Agent系统，提升自动化能力</span></span>
<span class="line"><span></span></span>
<span class="line"><span>任职要求：</span></span>
<span class="line"><span>1. 本科及以上学历，计算机相关专业</span></span>
<span class="line"><span>2. 3年以上Python开发经验</span></span>
<span class="line"><span>3. 熟悉LangChain/LlamaIndex等AI框架</span></span>
<span class="line"><span>4. 有大模型API调用和Prompt工程经验</span></span>
<span class="line"><span>5. 熟悉向量数据库（Milvus/Pinecone等）</span></span></code></pre></div><p>翻译一下：</p><ul><li>&quot;本科及以上，计算机相关专业&quot; → 最好本科，不是计算机也行，关键是能力</li><li>&quot;3年以上Python&quot; → 实习生和应届生可以酌情放宽，社招的话这条比较硬</li><li>&quot;熟悉LangChain/LlamaIndex&quot; → 能用就行，不需要精通</li><li>&quot;Prompt工程经验&quot; → 会调API就行</li><li>&quot;熟悉向量数据库&quot; → 能跑通demo就行</li></ul><p><strong>这条JD的真实门槛：能写Python + 会调API + 有RAG/Agent的入门经验。</strong></p><p>3年经验对于社招是合理的，但1-2年也行。至于&quot;计算机相关专业&quot;……说实话，做过AI应用开发的人都知道，很多做得好的同事专业是生物、化学、机械，跟&quot;计算机&quot;八竿子打不着。</p><hr><h6 id="薪资现实" tabindex="-1">薪资现实 <a class="header-anchor" href="#薪资现实" aria-label="Permalink to &quot;薪资现实&quot;">​</a></h6><p>2025-2026年的AI应用开发薪资：</p><table tabindex="0"><thead><tr><th>级别</th><th>月薪范围</th><th>备注</th></tr></thead><tbody><tr><td>初级（0-2年）</td><td>18-28K</td><td>入行薪资，大厂会更高</td></tr><tr><td>中级（2-5年）</td><td>30-50K</td><td>主力开发岗</td></tr><tr><td>高级（5年+）</td><td>50-80K</td><td>能带项目的级别</td></tr><tr><td>Agent架构师（资深）</td><td>80K-150K+</td><td>极度稀缺</td></tr></tbody></table><p>数据来源：脉脉高聘、猎聘、BOSS直聘等平台的公开数据综合。</p><p>注意这是base salary，不含年终奖（通常2-6个月）和股票。大厂总包可能是月薪×16甚至更多。</p><p>AI应用开发工程师比传统后端开发的薪资溢价约20-40%。Agent方向溢价更高，因为太缺人了。</p><p><strong>一句话总结：JD要看你能给的，别被&quot;完美候选人画像&quot;吓住。企业写着要A/B/C，实际上D（能干活）就够了。</strong></p><hr><h4 id="_1-4-真实转行案例集-8个不同背景的人怎么进来的" tabindex="-1">1.4 真实转行案例集：8个不同背景的人怎么进来的 <a class="header-anchor" href="#_1-4-真实转行案例集-8个不同背景的人怎么进来的" aria-label="Permalink to &quot;1.4 真实转行案例集：8个不同背景的人怎么进来的&quot;">​</a></h4><p>说了这么多理论，不如来看看真实的人是怎么转进来的。</p><p>我收集了8个不同背景的案例，涵盖了各种&quot;你以为很难&quot;的情况。看完你会发现：转行这事，没你想的那么难。</p><hr><h6 id="案例1-传统后端开发-28岁-java背景" tabindex="-1">案例1：传统后端开发，28岁，Java背景 <a class="header-anchor" href="#案例1-传统后端开发-28岁-java背景" aria-label="Permalink to &quot;案例1：传统后端开发，28岁，Java背景&quot;">​</a></h6><p><strong>背景</strong>：某二线城市，在传统企业做了4年Java，主要工作是写CRUD。薪资到顶也就20K，看不到上升空间。</p><p><strong>转行动机</strong>：公司在推AI转型，leader问谁愿意学，给了他一个内部试点项目的机会。</p><p><strong>入行路径</strong>：</p><ol><li>花2个月业余时间学LangChain，跟着官方文档做了几个小demo</li><li>在公司内部搭了一个合同条款审核的RAG系统（用开源文档做测试）</li><li>把这个经历写成简历项目，投了几家AI公司</li><li>面试了3家，拿了2个offer</li></ol><p><strong>现在的状态</strong>：入职某AI创业公司做应用开发，base 35K+期权。比起之前涨了60%。</p><p><strong>他说</strong>：最难的不是学技术，是迈出第一步开始投简历。之前觉得自己&quot;不是AI背景&quot;，其实企业更看重&quot;能不能干活&quot;。</p><hr><h6 id="案例2-前端开发-26岁-vue背景" tabindex="-1">案例2：前端开发，26岁，Vue背景 <a class="header-anchor" href="#案例2-前端开发-26岁-vue背景" aria-label="Permalink to &quot;案例2：前端开发，26岁，Vue背景&quot;">​</a></h6><p><strong>背景</strong>：北京某电商公司，做了2年前端。薪资还行但感觉前端天花板低，想转全栈又不想只做增删改查。</p><p><strong>转行动机</strong>：看到AI应用开发的薪资，加上公司技术栈也在往AI靠拢。</p><p><strong>入行路径</strong>：</p><ol><li>利用业余时间做了个小工具：用GPT-4 API做了一个&quot;小红书文案生成器&quot;，部署在Vercel上</li><li>把这个小工具的代码和思路整理成博客发出去</li><li>面试时被问到这个项目，滔滔不绝讲了20分钟</li><li>成功入职某教育科技公司的AI产品团队</li></ol><p><strong>现在的状态</strong>：AI产品研发工程师，35K。做的事情很有意思：用Agent做自动出题、自动批改。</p><p><strong>她说</strong>：前端转AI有个天然优势——对用户体验敏感。做AI产品很需要这种视角。</p><hr><h6 id="案例3-数据分析师-29岁-sql和excel专家" tabindex="-1">案例3：数据分析师，29岁，SQL和Excel专家 <a class="header-anchor" href="#案例3-数据分析师-29岁-sql和excel专家" aria-label="Permalink to &quot;案例3：数据分析师，29岁，SQL和Excel专家&quot;">​</a></h6><p><strong>背景</strong>：某咨询公司，做了4年数据分析。Python只会一点点，但SQL和Excel贼溜，做报表是专家。</p><p><strong>转行动机</strong>：AI时代，数据分析师要被替代的焦虑很重。不想等着被替代，想转成&quot;会用AI的数据分析师&quot;。</p><p><strong>入行路径</strong>：</p><ol><li>先学Python基础（专门学数据分析相关的部分）</li><li>学了LangChain和RAG的原理</li><li>把自己在咨询公司积累的&quot;行业知识&quot;包装成优势</li><li>面试时主打&quot;业务理解+AI能力&quot;的组合</li></ol><p><strong>现在的状态</strong>：某金融科技公司的AI产品经理，40K。做的核心工作是：让AI能理解金融报告，生成投资摘要。</p><p><strong>她说</strong>：很多人觉得分析师要会写模型才能转AI。其实&quot;理解业务&quot;+ &quot;会用工具&quot;就够了。我的行业知识是纯码农没有的。</p><hr><h6 id="案例4-运营转行-24岁-无编程背景" tabindex="-1">案例4：运营转行，24岁，无编程背景 <a class="header-anchor" href="#案例4-运营转行-24岁-无编程背景" aria-label="Permalink to &quot;案例4：运营转行，24岁，无编程背景&quot;">​</a></h6><p><strong>背景</strong>：某互联网公司做用户运营，零编程基础，但日常工作经常用ChatGPT写文案、做分析。</p><p><strong>转行动机</strong>：AI冲击下觉得运营迟早要被替代，想转做&quot;AI运营&quot;方向。</p><p><strong>入行路径</strong>：</p><ol><li>花了4个月业余时间学Python（从零开始）</li><li>做了几个用Coze（字节的AI应用平台）搭建的demo</li><li>面试时说：我是运营里最懂AI的、AI人里最懂运营的</li><li>去了家AI SaaS公司做AI产品运营，后来转了产品经理</li></ol><p><strong>现在的状态</strong>：AI产品经理，28K。虽然起步薪资不高，但成长很快。</p><p><strong>她说</strong>：最难的是转行的头3个月，Python真的学不进去。后来找了个学习方法：不要学&quot;编程&quot;，要学&quot;怎么用编程解决我工作中的问题&quot;。带着问题学，事半功倍。</p><hr><h6 id="案例5-机械工程师-31岁-研究生学历" tabindex="-1">案例5：机械工程师，31岁，研究生学历 <a class="header-anchor" href="#案例5-机械工程师-31岁-研究生学历" aria-label="Permalink to &quot;案例5：机械工程师，31岁，研究生学历&quot;">​</a></h6><p><strong>背景</strong>：某制造业公司，做了5年机械设计。会MATLAB，不会Python，但数学功底不错。</p><p><strong>转行动机</strong>：制造业不景气，想趁35岁之前转行。</p><p><strong>入行路径</strong>：</p><ol><li>辞职后花了6个月全职学习（有点冒险，但他是破釜沉舟型的）</li><li>Python + Django/Flask + LangChain + RAG全套学下来</li><li>在GitHub上复现了几个开源的RAG项目</li><li>面试时被问到了很多工程化问题，之前在制造业积累的&quot;系统思维&quot;派上了用场</li></ol><p><strong>现在的状态</strong>：某智能制造公司的AI应用开发，38K。虽然跨行有点大，但制造业背景反而成了差异化优势。</p><p><strong>他说</strong>：机械和AI看似不搭，但制造业现在最需要AI落地。我在制造业的经验，让我能理解工厂真正需要什么。</p><hr><h6 id="案例6-测试工程师-27岁" tabindex="-1">案例6：测试工程师，27岁 <a class="header-anchor" href="#案例6-测试工程师-27岁" aria-label="Permalink to &quot;案例6：测试工程师，27岁&quot;">​</a></h6><p><strong>背景</strong>：某互联网公司，做了3年功能测试，偶尔写点自动化脚本（Selenium）。</p><p><strong>转行动机</strong>：测试岗位在AI时代价值下降，想往AI方向靠。</p><p><strong>入行路径</strong>：</p><ol><li>从&quot;AI测试&quot;方向切入——AI应用需要大量测试（幻觉检测、输出质量评估）</li><li>学了Python + pytest + LangChain</li><li>在公司内部转岗到AI测试组，做了大模型评测平台</li><li>积累了一年后，跳槽到AI公司做&quot;AI应用测试工程师&quot;</li></ol><p><strong>现在的状态</strong>：AI应用测试工程师，32K。薪资涨了不算多，但赛道完全不一样了。</p><p><strong>她说</strong>：测试转AI有个捷径——从AI测试切入。纯测功能没有壁垒，但测AI应用是稀缺能力。</p><hr><h6 id="案例7-应届毕业生-22岁-计算机本科" tabindex="-1">案例7：应届毕业生，22岁，计算机本科 <a class="header-anchor" href="#案例7-应届毕业生-22岁-计算机本科" aria-label="Permalink to &quot;案例7：应届毕业生，22岁，计算机本科&quot;">​</a></h6><p><strong>背景</strong>：普通本科（非985/211），计算机专业，有基本编程能力但没接触过AI。</p><p><strong>转行动机</strong>：校招想进大厂但竞争太激烈，想走AI方向曲线救国。</p><p><strong>入行路径</strong>：</p><ol><li>毕业前2个月学完了LangChain官方教程</li><li>在简历上重点写了学校的AI相关课程项目（虽然很水）</li><li>避开大厂，专投中小公司和创业公司</li><li>运气不错，拿到一家AI创业公司的offer</li></ol><p><strong>现在的状态</strong>：AI应用开发工程师，20K（应届生）。虽然起步薪资不高，但成长空间大。</p><p><strong>他说</strong>：没有项目经验就创造经验。我把课程设计改造成了&quot;RAG应用&quot;，虽然很简陋，但至少让面试官知道我知道RAG是什么。</p><hr><h6 id="案例8-35岁传统it-运维背景" tabindex="-1">案例8：35岁传统IT，运维背景 <a class="header-anchor" href="#案例8-35岁传统it-运维背景" aria-label="Permalink to &quot;案例8：35岁传统IT，运维背景&quot;">​</a></h6><p><strong>背景</strong>：某传统企业IT运维，做了10年服务器维护。熟悉Linux、Docker，但不太会写代码。</p><p><strong>转行动机</strong>：运维在云化浪潮下被挤压，想转型但年龄已经35了。</p><p><strong>入行路径</strong>：</p><ol><li>学的方向是&quot;AI应用部署&quot;——结合自己的运维经验</li><li>重点学Docker、FastAPI、vLLM部署</li><li>面试时说：我可能是运维里最懂AI部署的、AI开发里最懂运维的</li><li>去了家AI公司做AI应用部署工程师</li></ol><p><strong>现在的状态</strong>：AI应用运维工程师，40K。虽然不写业务代码，但AI应用的部署、监控、运维全是他负责。</p><p><strong>他说</strong>：35岁转行确实不容易，但AI运维是个相对蓝海的领域。企业需要有人能把AI应用真正跑起来、稳定跑起来。</p><hr><h6 id="案例总结-共同规律" tabindex="-1">案例总结：共同规律 <a class="header-anchor" href="#案例总结-共同规律" aria-label="Permalink to &quot;案例总结：共同规律&quot;">​</a></h6><p>看完这8个案例，你发现什么规律了吗？</p><ol><li><strong>没有人是从零突然变成AI专家的</strong>。都是一边学一边投，简历上都是&quot;做过什么&quot;而不是&quot;会什么&quot;。</li><li><strong>差异化比全面更重要</strong>。你有运营背景、他有制造业背景、我有测试背景——这些反而是优势。</li><li><strong>低门槛入行是真实存在的</strong>。案例4从零编程开始，案例6从测试切入——不是所有人都是&quot;科班转AI&quot;。</li><li><strong>薪资涨幅明显</strong>。最差的案例也涨薪30%以上，大部分是50%+。</li><li><strong>年龄不是绝对门槛</strong>。35岁转行的也有，但确实需要更多准备和更精准的定位。</li></ol><p><strong>一句话总结：转行这事，没有&quot;准备好&quot;的那一天。你缺的只是一个入行机会，而不是一个完美的知识体系。</strong></p><hr><h4 id="本章行动清单" tabindex="-1">本章行动清单 <a class="header-anchor" href="#本章行动清单" aria-label="Permalink to &quot;本章行动清单&quot;">​</a></h4><ol><li><p><strong>明确你的定位</strong>：确认你想做的是&quot;AI应用开发&quot;，而不是&quot;AI研究&quot;。这两个方向的前置要求差了十万八千里。</p></li><li><p><strong>评估当前技能</strong>：对照&quot;硬门槛&quot;清单——Python能力、API调用经验、对AI框架的熟悉度。你缺什么，就补什么。</p></li><li><p><strong>别被JD吓住</strong>：把JD翻译成真实要求。你不需要满足所有条件才能投，60%匹配度就可以开始投了。</p></li><li><p><strong>选一个案例对号入座</strong>：上面8个案例，总有一个跟你背景类似。看看他们怎么做的，给自己找信心。</p></li><li><p><strong>做一个小demo</strong>：不管你用什么方式，学了多久，找一个能展示的东西。哪怕是个很简陋的RAG demo，也比&quot;我学过但没做过&quot;强一百倍。</p></li><li><p><strong>开始投简历</strong>：别等准备好再投。边投边学，投的过程就是学习的过程。面试一次，比你看书一个月学得多。</p></li></ol><hr><blockquote><p><strong>下章预告</strong>：第二章我会讲&quot;为什么先混进去是理性策略&quot;——你会发现，边干边学的效率远超闭门苦读，以及如何克服&quot;我不够格&quot;的心理障碍。</p></blockquote>`,195)])])}const A=o(p,[["render",l]]);export{q as __pageData,A as default};
